from dataclasses import dataclass

@dataclass(frozen=True)
class Color:
    r: int
    g: int
    b: int

red = Color(255, 0, 0)
print(red)
print(red.r)

try:
    red.r = 100  # should fail
except Exception as e:
    print(f"Error: {type(e).__name__}")

